---@class LCityPath
local LCityPath = classX("LCityPath",nil)

function LCityPath:ctor()

    ---@type table<number,LCityPathObj> 路径对象
    self._pathObjs = {}

    ---@type GameObject
    self._pathListGo = nil

    ---@type Transform
    self._pathListTrans = nil

    ---@type GameObject
    self._npcRootGo = nil

    ---@type Transform
    self._npcRootTrans = nil

    ---@type table<count:number,pointTransList:table<Transform>>
    self._pathListInfos = {}

    ---@type LxTimer
    self._timer = nil

    ---@type GameObject[]
    self._objMaps = {}
end

function LCityPath:Dispose()
    for k,v in pairs(self._pathObjs) do
        v:Dispose()
    end
    self._pathObjs = nil

    for k,obj in pairs(self._objMaps) do
        LxResUtil.DestroyObject(obj)
    end

    table.dispose(self)
end

function LCityPath:InitPathListGo(go)
    self._pathListGo = go
    self._pathListTrans = go.transform
    self:InitPathList()
end

function LCityPath:SetHeroRoot(npcRoot)
    self._npcRootGo = npcRoot
    self._npcRootTrans = npcRoot.transform
end

function LCityPath:InitPathList()
    local listTrans = self._pathListTrans

    local pathLists = {}
    local count = listTrans.childCount
    for i = 1,count do
        ---@type Transform
        local trans = listTrans:Find("Path" .. i)
        if trans then
            ---@type table<Transform>
            local pathPointTrans = {}
            local transChildCount = trans.childCount
            for idx = 1,transChildCount do
                ---@type Transform
                local pointTrans = trans:Find(tostring(idx))
                if pointTrans then
                    table.insert(pathPointTrans,pointTrans)
                end
            end
            table.insert(pathLists,{
                pointTransList = pathPointTrans,
                count = transChildCount,
            })
        end
    end
    self._pathListInfos = pathLists

    self:TestPathObjs()
end

function LCityPath:TestPathObjs()
    local random = math.random(1,5)
    random = 5
    local pathListInfos = self._pathListInfos
    local len = #pathListInfos
    for i = 1,random do
        local objObj = LxResUtil.NewGameObject("pathObj_" .. i)
        self._objMaps[i] = objObj

        local randomPath = math.random(1,len)
        local points = pathListInfos[randomPath].pointTransList
        local randomPosIdx = math.random(1,#points)
        local firstPoint = points[randomPosIdx]

        ---@type Transform
        local objTrans = objObj.transform
        objTrans:SetParent(self._npcRootTrans)
        objTrans.localScale = Vector3.one
        objTrans.localPosition = Vector3.zero
        objTrans.localRotation = Quaternion.identity
        objTrans.position = firstPoint.position


        local pathObj = require("LApp.gameplay.city.path.LCityPathObj"):new()
        pathObj:SetParent(objTrans)
        pathObj:SetPointIdx(randomPosIdx)
        pathObj:SetPathPoints(points)

        pathObj:TestData()
        table.insert(self._pathObjs,pathObj)
    end
end


return LCityPath